#!/bin/bash
# Removes CLAUDE.md files auto-generated by claude-mem's folder indexer
# and strips <claude-mem-context> blocks from CLAUDE.md files with real content.
#
# Why: claude-mem creates CLAUDE.md files in every directory it indexes.
# These pollute the command/skill namespace and cause confusion.
# This hook runs at SessionStart to clean them up.

# 1. Clean ~/.claude/ artifacts (preserve main config)
find ~/.claude -name "CLAUDE.md" \
  ! -path "$HOME/.claude/CLAUDE.md" \
  -delete 2>/dev/null

# 2. Strip <claude-mem-context> blocks from project CLAUDE.md files
# Add your project directories here:
PROJECT_DIRS=(
  # "$HOME/projects/my-project"
  # "$HOME/research/my-research"
)

for dir in "${PROJECT_DIRS[@]}"; do
  [ -d "$dir" ] || continue

  while IFS= read -r -d '' file; do
    [[ "$file" == */node_modules/* ]] && continue

    # Strip <claude-mem-context>...</claude-mem-context> blocks
    sed -i '' '/<claude-mem-context>/,/<\/claude-mem-context>/d' "$file"

    # If file is now empty or whitespace-only, delete it
    if [ ! -s "$file" ] || ! grep -q '[^[:space:]]' "$file"; then
      rm "$file"
    fi
  done < <(find "$dir" -name "CLAUDE.md" -not -path "*/node_modules/*" -print0 2>/dev/null)
done
